<template>
  <VaForm ref="form" class="m-auto" style="width: 300px" @submit.prevent="submit">
    <h1 class="font-semibold text-2xl mb-4 hidden sm:block">CRM</h1>
    <VaInput
      v-model="formData.email"
      :rules="[validators.required, validators.email]"
      class="mb-4"
      label="Usuario"
      type="email"
    />
    <VaValue v-slot="isPasswordVisible" :default-value="false">
      <VaInput
        v-model="formData.password"
        :rules="[validators.required]"
        :type="isPasswordVisible.value ? 'text' : 'password'"
        class="mb-4"
        label="Contraseña"
        @clickAppendInner.stop="isPasswordVisible.value = !isPasswordVisible.value"
      >
        <template #appendInner>
          <VaIcon
            :name="isPasswordVisible.value ? 'mso-visibility_off' : 'mso-visibility'"
            class="cursor-pointer"
            color="secondary"
          />
        </template>
      </VaInput>
    </VaValue>

    <div class="flex justify-center">
      <VaButton class="w-full py-2" type="submit" :disabled="!isValid" @click="submit"> Acceder </VaButton>
    </div>
  </VaForm>
</template>

<script lang="ts" setup>
import { reactive } from 'vue'
import { useRouter } from 'vue-router'
import { useForm, useToast } from 'vuestic-ui'
import { validators } from '../../services/utils'
import { apiAuth } from '../../core/requests/Auth'

const { isValid, validate } = useForm('form')
const { push } = useRouter()
const { init, notify } = useToast()

const formData = reactive({
  email: '',
  password: '',
})

const submit = async () => {
  if (validate()) {
    const authData: any = await apiAuth({
      password: formData.password,
      username: formData.email,
    })

    if (authData.status == true) {
      localStorage.setItem('__token', authData.token)
      localStorage.setItem('__user', JSON.stringify(authData.user))
      init({ message: 'Iniciaste sesión correctamente', color: 'success' })
      push({ name: 'dashboard' })
    } else {
      notify({ message: 'Error al iniciar sesión', color: 'danger' })
    }
  }
}
</script>
